int nextBalanced(int n) {
    while (true) {
        n++;
        Map<Integer, Integer> digitCount = new HashMap<>();
        int temp = n;
        while (temp != 0) {
            digitCount.put(temp % 10, digitCount.getOrDefault(temp % 10, 0) + 1);
            temp /= 10;
        }
        boolean balanced = true;
        for (Map.Entry<Integer, Integer> entry : digitCount.entrySet()) {
            if (!entry.getKey().equals(entry.getValue())) {
                balanced = false;
                break;
            }
        }
        if (balanced) return n;
    }
}
```

